import { test, expect } from '@playwright/test';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const localUrl = `file://${path.resolve(__dirname, 'target-app/async_page.html')}`;

test.describe('Async Loading Tests', () => {
    test('should handle late-loading elements with smart waiting', async ({ page }) => {
      await page.goto(localUrl);
      const lateButton = page.locator('#late-loading-button');
      await lateButton.waitFor({ state: 'visible', timeout: 10000 });
      await expect(lateButton).toBeVisible();
      await expect(lateButton).toContainText('Click Me Finally');
    });
});
